sql:
SELECT trans_id, c_fips, average_commute_time
FROM transportation
WHERE average_commute_time > (SELECT AVG(average_commute_time) FROM transportation);

SELECT total_spending, per_capita_spending 
FROM economics 
WHERE c_fips = 12345;

SELECT housing_id, c_fips, median_home_value, homeownership_rate
FROM housing
WHERE renter_occupied_rate > 50;

SELECT trans_id, c_fips, average_commute_time, public_transit_usage, bikeability_score
FROM transportation
WHERE average_commute_time > 30.0 AND public_transit_usage > 10.0;

SELECT c.county_name, c.population_density
FROM counties c
WHERE c.population_density > (SELECT AVG(population_density) FROM counties);

SELECT DISTINCT health_id
FROM health
ORDER BY life_expectancy;

SELECT air_quality_index
FROM environment
WHERE green_space_percentage > 40;

SELECT gini_coefficient
FROM economic_indicators
WHERE c_fips = (SELECT c_fips FROM counties WHERE county_name = 'Des Moines County');

SELECT crime_rate
FROM public_safety
WHERE c_fips = 1;

external_knowledge:
- Densely populated counties: those with a population density greater than 200 people per square mile;
- Smaller land areas: counties with an area less than 1000 square miles;
- Economic indicators: per capita spending, GDP growth rate, and inflation rate;
- Specific day: March 1, 2022, which is early in the spring season.
